// Replace each deprecated construct with its modern equivalent:

// 1. now -> block.timestamp
uint256 deadline = block.timestamp + 1 days;

// 2. throw -> revert() or a custom error (refunds remaining gas)
error Unauthorized(address caller);
if (msg.sender != owner) revert Unauthorized(msg.sender);

// 3. sha3(...) -> keccak256(...)
bytes32 hash = keccak256(abi.encodePacked(data));

// 4. suicide(addr) -> selfdestruct(addr)
// (and reconsider whether selfdestruct is needed at all; it is itself deprecated)
selfdestruct(payable(owner));

// 5. var -> explicit types
uint256 i = 0; // instead of: var i = 0; (var inferred uint8 here, overflowing at 256)
